CREATE OR REPLACE FUNCTION trigger_fct_tbu_sc_kep_t_monthly_receive_d() RETURNS trigger AS $BODY$
declare
  li_count integer;
  ls_agent_no sc_kep_t_monthly_receive.agent_no%type;
  ls_agent_active char;
BEGIN
  BEGIN
--return ;
  if (OLD.money_amount  <> NEW.money_amount)
    or (OLD.principal_of_loan <> NEW.principal_of_loan)
    or (OLD.interest <> NEW.interest) then
    BEGIN
      select agent_no , agent_active
      into STRICT ls_agent_no ,ls_agent_active
      from sc_kep_t_monthly_receive
      where membership_no = NEW.membership_no
      and receive_year = NEW.receive_year
      and receive_month = NEW.receive_month
      and seq_no = NEW.seq_no;
    exception when others then ls_agent_active := null;
    end;
    if ls_agent_active = '1' then
      CALL spa_dberror('T24:ทะเบียน('||trim(both NEW.membership_no)||')ไม่สามารถแก้ไขยอดเงินได้ เพราะได้ตั้งลูกหนี้หน่วย('||trim(both ls_agent_no)||') ไปแล้ว');
    end if;
  end if;
null;
  END;
RETURN NEW;
end
$BODY$
